"use strict";parserFactory.register("xbanxia.cc",()=>new XbanxiaParser);class XbanxiaParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("#content-list > div.book-list.clearfix > ul");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("#nr1")}findChapterTitle(e){return e.querySelector("#nr_title")}extractTitleImpl(e){return e.querySelector(".book-describe h1")}extractAuthor(e){let t=e.querySelector(".book-describe a[href*='/author/']");return t?.textContent??super.extractAuthor(e)}extractLanguage(){return"zh"}extractSubject(e){return this.extractLabeledValue(e,["类型","類型"])}extractDescription(e){let t=e.querySelector(".describe-html");return t?.textContent?.trim()??""}findCoverImageUrl(e){let t=e.querySelector("#content-list > div.book-intro.clearfix > div.book-img img");return t?.getAttribute("data-original")??t?.src??null}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"script, span"),super.removeUnwantedElementsFromContentElement(e)}extractLabeledValue(e,t){let r=[...e.querySelectorAll(".book-describe p")];for(let e of r){let r=e.textContent?.replace(/\s+/g," ").trim();if(null!=r)for(let e of t){let t=r.match(new RegExp(`^${e}[：:︰]\\s*(.+)$`));if(null!=t)return t[1].trim()}}return""}}